import java.lang.reflect.*;
public class ConstructorReflect {
    static class Greeter {
        String prefix;
        Greeter(String p) { prefix = p; }
        String greet(String name) { return prefix + name; }
    }
    public static void main(String[] args) throws Exception {
        Constructor<Greeter> ctor = Greeter.class.getDeclaredConstructor(String.class);
        Greeter g = ctor.newInstance("Hello, ");
        Method m = Greeter.class.getDeclaredMethod("greet", String.class);
        System.out.println(m.invoke(g, "World"));
        System.out.println(ctor.getParameterTypes()[0].getSimpleName());
    }
}
